+// MARK: - Config Persistence
+
+/// Persists user settings (like model path) across app launches
+class ZellConfig {
+    static let shared = ZellConfig()
+
+    private let configURL: URL
+    private var config: [String: Any] = [:]
+
+    private init() {
+        // Store config in ~/Library/Application Support/Zell/config.json
+        let appSupport = FileManager.default.urls(for: .applicationSupportDirectory, in: .userDomainMask).first!
+        let zellDir = appSupport.appendingPathComponent("Zell")
+        configURL = zellDir.appendingPathComponent("config.json")
+
+        // Create directory if needed
+        try? FileManager.default.createDirectory(at: zellDir, withIntermediateDirectories: true)
+
+        // Load existing config
+        load()
+    }
+
+    private func load() {
+        guard let data = try? Data(contentsOf: configURL),
+              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
+            return
+        }
+        config = json
+    }
+
+    private func save() {
+        guard let data = try? JSONSerialization.data(withJSONObject: config, options: .prettyPrinted) else {
+            return
+        }
+        try? data.write(to: configURL)
+    }
+
+    var lastModelPath: String? {
+        get { config["lastModelPath"] as? String }
+        set {
+            config["lastModelPath"] = newValue
+            save()
+        }
+    }
+}
